import React from 'react';
import { Routes, Route, Link } from 'react-router-dom';

const AdminDashboard = () => {
  return (
    <div className="container">
      <h1>Admin Dashboard</h1>
      <div className="admin-nav">
        <Link to="/admin/products" className="btn">Manage Products</Link>
        <Link to="/admin/orders" className="btn">Manage Orders</Link>
        <Link to="/admin/users" className="btn">View Users</Link>
      </div>
      <Routes>
        <Route path="/" element={<div>Welcome to Admin Panel</div>} />
        <Route path="/products" element={<div>Product Management</div>} />
        <Route path="/orders" element={<div>Order Management</div>} />
        <Route path="/users" element={<div>User Management</div>} />
      </Routes>
    </div>
  );
};

export default AdminDashboard;
